<template><Head title="Subscription Plans" /><DealerLayout title="Subscription Plans" eyebrow="Listing capacity"><section class="rounded-lg border p-5" :class="currentPlan?'border-teal-100 bg-teal-50':'border-orange-100 bg-orange-50'"><p class="text-xs font-semibold uppercase" :class="currentPlan?'text-teal-700':'text-orange-700'">{{ currentPlan?'Active subscription':'Subscription required' }}</p><h2 class="mt-2 text-2xl font-semibold text-slate-950">{{ currentPlan?currentPlan.name:'Choose a plan to start listing cars.' }}</h2><p v-if="currentPlan" class="mt-2 text-sm font-semibold text-slate-600">{{ currentPlan.active_listings }} of {{ currentPlan.listing_limit }} listings used. Valid until {{ currentPlan.expires_at }}.</p></section><section class="mt-5 grid gap-4 md:grid-cols-2 xl:grid-cols-3"><article v-for="plan in plans" :key="plan.id" class="flex flex-col rounded-lg border bg-white p-5 shadow-sm" :class="plan.is_current?'border-teal-300':'border-slate-200'"><span v-if="plan.is_current" class="self-start rounded-md bg-teal-50 px-2.5 py-1 text-xs font-semibold text-teal-700">Current plan</span><h3 class="mt-3 text-xl font-semibold text-slate-950">{{ plan.name }}</h3><p class="mt-2 text-3xl font-semibold text-teal-700">{{ plan.price===0?'Free':money(plan.price) }}</p><p class="mt-1 text-sm font-bold text-slate-500">{{ plan.duration_days }} days</p><div class="mt-5 space-y-2 text-sm font-semibold text-slate-600"><p>{{ plan.listing_limit }} car listings</p><p>{{ plan.duration_days }} days validity</p><p v-if="plan.description">{{ plan.description }}</p></div><Link v-if="!plan.is_current" :href="plan.show_url" class="mt-6 inline-flex min-h-12 items-center justify-center rounded-lg bg-slate-950 px-4 text-sm font-semibold text-white hover:bg-teal-700">Review plan</Link><button v-else class="mt-6 min-h-12 rounded-lg bg-teal-50 text-sm font-semibold text-teal-700" disabled>Active</button></article></section></DealerLayout></template>
<script setup lang="ts">import{Head,Link}from'@inertiajs/vue3';import DealerLayout from '@/Layouts/DealerLayout.vue';defineProps<{plans:Array<any>;currentPlan:any|null}>();const money=(v:number)=>`Rs ${new Intl.NumberFormat('en-IN').format(v||0)}`;</script>
